#!/usr/bin/env node
/**
 * ForgeNexus SQLite → KuzuDB Migration Script
 *
 * Purpose: Migrate existing ForgeNexus SQLite index to the new KuzuDB graph backend.
 *
 * What gets migrated:
 *   - nodes       → CodeNode table
 *   - edges       → per-type rel tables (CALLS, IMPORTS, etc.)
 *   - communities → Community table
 *   - processes   → Process table
 *   - Registry    → RepoRegistry + RepoCall tables
 *
 * What does NOT migrate:
 *   - Embeddings (re-generated by forgenexus analyze --embeddings)
 *   - FTS index   (re-built by KuzuDB FTS extension automatically)
 *   - Groups      (new feature, not in SQLite)
 *
 * Usage:
 *   node scripts/migrate-sqlite-to-kuzu.js [--dry-run] [--verbose]
 *
 * Prerequisites:
 *   npm install --prefix forgenexus
 *   npx forgenexus build
 */

import { Database } from 'better-sqlite3';
import { Database as KuzuDB } from 'kuzu';
import { writeFileSync, existsSync, readFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));

// ─── CLI Args ──────────────────────────────────────────────────────────────────

const args = process.argv.slice(2);
const DRY_RUN = args.includes('--dry-run') || args.includes('-n');
const VERBOSE = args.includes('--verbose') || args.includes('-v');

function log(...msg) {
  if (VERBOSE) console.log('[migrate]', ...msg);
}

function warn(...msg) {
  console.warn('[migrate] ⚠️ ', ...msg);
}

function die(...msg) {
  console.error('[migrate] ❌ ', ...msg);
  process.exit(1);
}

// ─── Path Resolution ──────────────────────────────────────────────────────────

function findSqliteDb(repoPath) {
  // Try .forgenexus/ directory
  const paths = [
    join(repoPath, '.forgenexus', 'forgenexus.db'),
    join(repoPath, '.forgenexus', 'forgenexus.sqlite'),
    join(repoPath, '.forgenexus', 'data.db'),
    join(repoPath, '.forgewright', 'forgenexus.db'),
    join(repoPath, 'forgenexus.db'),
  ];
  for (const p of paths) {
    if (existsSync(p)) {
      log(`Found SQLite DB at: ${p}`);
      return p;
    }
  }
  return null;
}

function resolveOutputPath(repoPath) {
  // Output path for the new KuzuDB database
  const dir = join(repoPath, '.forgenexus');
  return join(dir, 'forgenexus.kuzu');
}

// ─── Schema ───────────────────────────────────────────────────────────────────

const KUZU_SCHEMA = `
LOAD EXTENSION fts;
LOAD EXTENSION vector;
LOAD EXTENSION json;

CREATE NODE TABLE IF NOT EXISTS CodeNode(
  uid        STRING PRIMARY KEY,
  type       STRING NOT NULL,
  name       STRING NOT NULL,
  filePath   STRING NOT NULL,
  line       INT64  NOT NULL,
  endLine    INT64  NOT NULL,
  columnNum  INT64,
  returnType STRING,
  paramCount INT64,
  declaredType STRING,
  language   STRING,
  signature  STRING,
  community  STRING,
  process    STRING,
  embedding  DOUBLE[384]
) COPYS(0);

CREATE NODE TABLE IF NOT EXISTS Community(
  id          STRING PRIMARY KEY,
  name        STRING NOT NULL,
  keywords    STRING,
  description STRING,
  cohesion    DOUBLE DEFAULT 0
) COPYS(0);

CREATE NODE TABLE IF NOT EXISTS Process(
  id              STRING PRIMARY KEY,
  name            STRING NOT NULL,
  type            STRING NOT NULL,
  entryPointUid   STRING NOT NULL,
  terminalUids    STRING,
  communities     STRING
) COPYS(0);

CREATE REL TABLE IF NOT EXISTS CONTAINS(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS DEFINES(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS CALLS(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS IMPORTS(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS EXTENDS(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS IMPLEMENTS(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS HAS_METHOD(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS HAS_PROPERTY(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS ACCESSES(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS OVERRIDES(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS MEMBER_OF(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS STEP_IN_PROCESS(FROM CodeNode TO Process, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS HANDLES_ROUTE(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS FETCHES(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS HANDLES_TOOL(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS ENTRY_POINT_OF(FROM CodeNode TO Process, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS QUERIES(FROM CodeNode TO CodeNode, ANTISYMMETRIC, MANY-TO-ONE);
CREATE REL TABLE IF NOT EXISTS IN_COMMUNITY(FROM CodeNode TO Community, ANTISYMMETRIC, MANY-TO-ONE);

CREATE NODE TABLE IF NOT EXISTS RepoRegistry(
  name        STRING PRIMARY KEY,
  path        STRING NOT NULL,
  dbPath      STRING NOT NULL,
  indexedAt   STRING NOT NULL,
  lastCommit  STRING,
  stats       STRING,
  language    STRING DEFAULT 'unknown'
) COPYS(0);

CREATE REL TABLE IF NOT EXISTS REPO_CALLS(FROM RepoRegistry TO RepoRegistry, SYMMETRIC, ONE-TO-ONE);

CREATE FTS INDEX ON CodeNode(name, signature, filePath);
`;

// ─── Migration ────────────────────────────────────────────────────────────────

function migrate(sqlitePath, kuzuPath, repoPath) {
  log('Opening SQLite DB:', sqlitePath);
  const sqlite = new Database(sqlitePath, { readonly: true });

  if (DRY_RUN) {
    warn('DRY RUN mode — no changes will be written');
  }

  // ── 1. Verify source schema ─────────────────────────────────────────────────
  const tables = sqlite
    .prepare("SELECT name FROM sqlite_master WHERE type='table' ORDER BY name")
    .all()
    .map((r) => r.name);
  log('SQLite tables:', tables);

  if (!tables.includes('nodes')) die('Source DB missing "nodes" table — not a valid ForgeNexus SQLite DB');
  if (!tables.includes('edges')) die('Source DB missing "edges" table — not a valid ForgeNexus SQLite DB');

  // ── 2. Count rows ────────────────────────────────────────────────────────────
  const nodeCount = sqlite.prepare('SELECT COUNT(*) as c FROM nodes').get().c;
  const edgeCount = sqlite.prepare('SELECT COUNT(*) as c FROM edges').get().c;
  const communityCount = tables.includes('communities')
    ? sqlite.prepare('SELECT COUNT(*) as c FROM communities').get().c
    : 0;
  const processCount = tables.includes('processes')
    ? sqlite.prepare('SELECT COUNT(*) as c FROM processes').get().c
    : 0;
  const registryCount = tables.includes('registry')
    ? sqlite.prepare('SELECT COUNT(*) as c FROM registry').get().c
    : 0;

  console.log(`Source DB stats:`);
  console.log(`  nodes:      ${nodeCount}`);
  console.log(`  edges:      ${edgeCount}`);
  console.log(`  communities: ${communityCount}`);
  console.log(`  processes:  ${processCount}`);
  console.log(`  registry:   ${registryCount}`);

  if (DRY_RUN) {
    warn('DRY RUN — stopping here');
    sqlite.close();
    return;
  }

  // ── 3. Remove existing KuzuDB if present ─────────────────────────────────────
  if (existsSync(kuzuPath)) {
    warn(`Removing existing KuzuDB at: ${kuzuPath}`);
    const { unlinkSync, rmdirSync } = await import('fs').catch(() => ({ unlinkSync: () => {}, rmdirSync: () => {} }));
    try {
      const { rmSync } = await import('fs');
      rmSync(kuzuPath, { recursive: true, force: true });
    } catch {
      // try rm -rf via shell
      const { execSync } = await import('child_process');
      try { execSync(`rm -rf "${kuzuPath}"`); } catch {}
    }
  }

  // ── 4. Create KuzuDB ─────────────────────────────────────────────────────────
  log('Creating KuzuDB at:', kuzuPath);
  const kuzu = new KuzuDB(kuzuPath);
  const conn = kuzu.connect();

  // Apply schema
  log('Applying KuzuDB schema...');
  for (const stmt of KUZU_SCHEMA.split(';').filter((s) => s.trim())) {
    try {
      conn.query(stmt + ';');
    } catch (err) {
      warn(`Schema stmt warning (may already exist): ${err.message}`);
    }
  }

  // ── 5. Migrate nodes ─────────────────────────────────────────────────────────
  console.log(`Migrating ${nodeCount} nodes...`);
  const BATCH = 1000;
  const nodes = sqlite.prepare(`
    SELECT uid, type, name, file_path, line, end_line, column_num,
           return_type, parameter_count, declared_type, language,
           signature, community, process_name, embedding
    FROM nodes
  `);

  let migrated = 0;
  const insertNode = conn.prepare(
    'INSERT INTO CodeNode VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)'
  );

  for (const row of nodes.iterate()) {
    const emb = row.embedding
      ? (() => { try { return JSON.parse(row.embedding); } catch { return null; } })()
      : null;
    // embedding → DOUBLE[384] — store as list or null
    const embList = emb && Array.isArray(emb) ? emb : null;

    try {
      conn.query(
        `INSERT INTO CodeNode VALUES ('${row.uid}','${row.type}','${(row.name || '').replace(/'/g, "''")}','${(row.file_path || '').replace(/'/g, "''")}',${row.line || 0},${row.end_line || 0},${row.column_num || 'NULL'},${row.return_type ? `'${row.return_type.replace(/'/g, "''")}'` : 'NULL'},${row.parameter_count || 'NULL'},${row.declared_type ? `'${row.declared_type.replace(/'/g, "''")}'` : 'NULL'},${row.language ? `'${row.language}'` : 'NULL'},${row.signature ? `'${(row.signature || '').replace(/'/g, "''")}'` : 'NULL'},${row.community ? `'${row.community}'` : 'NULL'},${row.process_name ? `'${row.process_name.replace(/'/g, "''")}'` : 'NULL'},${embList ? `'${JSON.stringify(embList)}'` : 'NULL'})`
      );
      migrated++;
      if (migrated % BATCH === 0) {
        process.stdout.write(`  ${migrated}/${nodeCount}\r`);
      }
    } catch (err) {
      warn(`Failed to insert node ${row.uid}: ${err.message}`);
    }
  }
  console.log(`  nodes: ${migrated}/${nodeCount} migrated`);

  // ── 6. Migrate edges ─────────────────────────────────────────────────────────
  console.log(`Migrating ${edgeCount} edges...`);
  const edgeTypes = [
    'CALLS', 'IMPORTS', 'EXTENDS', 'IMPLEMENTS', 'HAS_METHOD', 'HAS_PROPERTY',
    'ACCESSES', 'OVERRIDES', 'MEMBER_OF', 'STEP_IN_PROCESS', 'HANDLES_ROUTE',
    'FETCHES', 'HANDLES_TOOL', 'ENTRY_POINT_OF', 'QUERIES', 'DEFINES', 'CONTAINS',
  ];

  let migratedEdges = 0;
  for (const edgeType of edgeTypes) {
    const rows = sqlite.prepare(
      `SELECT from_uid, to_uid, confidence, reason, step FROM edges WHERE type = ?`
    ).all(edgeType);

    if (rows.length === 0) continue;

    for (const row of rows) {
      try {
        conn.query(
          `INSERT INTO ${edgeType} VALUES ('${row.from_uid}','${row.to_uid}')`
        );
        migratedEdges++;
      } catch (err) {
        // Ignore edge insert errors (missing nodes, etc.)
      }
    }
    log(`  ${edgeType}: ${rows.length} edges`);
  }
  console.log(`  edges: ${migratedEdges}/${edgeCount} migrated`);

  // ── 7. Migrate communities ───────────────────────────────────────────────────
  if (communityCount > 0) {
    console.log(`Migrating ${communityCount} communities...`);
    const communities = sqlite.prepare(
      'SELECT id, name, keywords, description, cohesion FROM communities'
    ).all();
    for (const c of communities) {
      try {
        conn.query(
          `INSERT INTO Community VALUES ('${c.id}','${(c.name || '').replace(/'/g, "''")}',${c.keywords ? `'${c.keywords.replace(/'/g, "''")}'` : 'NULL'},${c.description ? `'${c.description.replace(/'/g, "''")}'` : 'NULL'},${c.cohesion || 0})`
        );

        // Re-insert IN_COMMUNITY edges
        const members = sqlite.prepare(
          'SELECT uid FROM nodes WHERE community = ?'
        ).all(c.id);
        for (const m of members) {
          try {
            conn.query(`INSERT INTO IN_COMMUNITY VALUES ('${m.uid}','${c.id}')`);
          } catch {}
        }
      } catch (err) {
        warn(`Community ${c.id} failed: ${err.message}`);
      }
    }
    console.log(`  communities: ${communities.length} migrated`);
  }

  // ── 8. Migrate processes ─────────────────────────────────────────────────────
  if (processCount > 0) {
    console.log(`Migrating ${processCount} processes...`);
    const procs = sqlite.prepare(
      'SELECT id, name, type, entry_point_uid, terminal_uids, communities FROM processes'
    ).all();
    for (const p of procs) {
      try {
        conn.query(
          `INSERT INTO Process VALUES ('${p.id}','${(p.name || '').replace(/'/g, "''")}','${p.type || 'unknown'}','${p.entry_point_uid || ''}',${p.terminal_uids ? `'${p.terminal_uids.replace(/'/g, "''")}'` : 'NULL'},${p.communities ? `'${p.communities.replace(/'/g, "''")}'` : 'NULL'})`
        );
      } catch (err) {
        warn(`Process ${p.id} failed: ${err.message}`);
      }
    }
    console.log(`  processes: ${procs.length} migrated`);
  }

  // ── 9. Migrate registry ─────────────────────────────────────────────────────
  if (registryCount > 0) {
    console.log(`Migrating ${registryCount} registry entries...`);
    const regs = sqlite.prepare(
      'SELECT name, path, db_path, indexed_at, last_commit, stats, language FROM registry'
    ).all();
    for (const r of regs) {
      try {
        conn.query(
          `INSERT INTO RepoRegistry VALUES ('${r.name}','${(r.path || '').replace(/'/g, "''")}','${(r.db_path || '').replace(/'/g, "''")}','${r.indexed_at || ''}',${r.last_commit ? `'${r.last_commit}'` : 'NULL'},${r.stats ? `'${r.stats.replace(/'/g, "''")}'` : 'NULL'},'${r.language || 'unknown'}')`
        );
      } catch (err) {
        warn(`Registry ${r.name} failed: ${err.message}`);
      }
    }
    console.log(`  registry: ${regs.length} migrated`);
  }

  // ── 10. Cleanup ──────────────────────────────────────────────────────────────
  conn.close();
  kuzu.destroy();
  sqlite.close();

  // ── 11. Write marker file ─────────────────────────────────────────────────────
  const markerPath = join(dirname(kuzuPath), 'migrated-from-sqlite.json');
  writeFileSync(
    markerPath,
    JSON.stringify(
      {
        migratedAt: new Date().toISOString(),
        sourceSqlite: sqlitePath,
        targetKuzu: kuzuPath,
        stats: { nodes: migrated, edges: migratedEdges, communities: communityCount, processes: processCount, registry: registryCount },
        note: 'Run: npx forgenexus analyze --embeddings to regenerate vector embeddings',
      },
      null,
      2
    )
  );

  console.log(`\n✅ Migration complete!`);
  console.log(`   KuzuDB: ${kuzuPath}`);
  console.log(`   Marker: ${markerPath}`);
  console.log(`\n   Next step: npx forgenexus analyze --embeddings`);
  console.log(`   (regenerates vector embeddings lost during migration)`);
}

// ─── Main ─────────────────────────────────────────────────────────────────────

const repoPath = args[0] || process.cwd();
const sqlitePath = findSqliteDb(repoPath);
const kuzuPath = resolveOutputPath(repoPath);

if (!sqlitePath) {
  die(
    `No SQLite database found in: ${repoPath}\n` +
      `  Searched: .forgenexus/forgenexus.db, .forgenexus/forgenexus.sqlite, .forgenexus/data.db`
  );
}

console.log(`\n🔄 ForgeNexus SQLite → KuzuDB Migration`);
console.log(`   Repo:   ${repoPath}`);
console.log(`   Source: ${sqlitePath}`);
console.log(`   Target: ${kuzuPath}`);
console.log('');

migrate(sqlitePath, kuzuPath, repoPath);
